const items = $input.all();
const out = [];
const fmt = (v) => (v == null || v === '') ? 'unknown' : String(v);
for (const it of items) {
  const r = it.json || {};
  const text =
    'RECIPIENT: ' + fmt(r.contact_name) + ' — ' + fmt(r.contact_title) + ' at ' + fmt(r.company_name) + ' (' + fmt(r.company_size) + ', HQ ' + fmt(r.hq_location) + ', industry: ' + fmt(r.industry) + ').\n' +
    'PROJECT: ' + fmt(r.project_name) + ' (' + fmt(r.region) + ', ' + fmt(r.state) + '). Type: ' + fmt(r.project_type) + ', stage: ' + fmt(r.timeline_stage) + '.\n\n' +
    'RESEARCH SUMMARY: ' + fmt(r.research_summary) + '\n' +
    'RECENT NEWS: ' + fmt(r.recent_news) + '\n\n' +
    'PERSONALIZATION HOOKS (use one verbatim or near-verbatim as the opener — do not invent a new one):\n' +
    '- Hook 1: ' + fmt(r.icebreaker_1) + '\n' +
    '- Hook 2: ' + fmt(r.icebreaker_2) + '\n\n' +
    'Write the email and the LinkedIn variant per the system rules.';
  out.push({ json: { lead_id: r.lead_id, input_text: text } });
}
return out;

const items = $input.all();
const inputs = $('Build Draft Input').all();
const selected = $('Select Researched Leads').all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const j = items[i].json || {};
  const ex = (j.output && typeof j.output === 'object') ? j.output : (typeof j === 'object' ? j : {});
  const base = (inputs[i] && inputs[i].json) ? inputs[i].json : {};
  const sel = (selected[i] && selected[i].json) ? selected[i].json : {};
  const email = (ex.email && typeof ex.email === 'object') ? ex.email : null;
  const linkedin = (ex.linkedin && typeof ex.linkedin === 'object') ? ex.linkedin : null;
  if (!email && !linkedin) continue;
  out.push({ json: {
    lead_id: base.lead_id,
    email: email,
    linkedin: linkedin,
    personalization_hooks: {
      icebreaker_1: sel.icebreaker_1 || null,
      icebreaker_2: sel.icebreaker_2 || null
    }
  } });
}
return out;
